			int tmp=fa(i);
			f[fa(i)]=fa(a);
			r[tmp]=(r[i]+opt+1+r[a])%2;
		}else
		{
			if((r[i]+r[a])%2!=(opt+1)%2)
			{
				printf("No answer");//判断无解
				return 0;
			}
		}	
	}
	for(int i=1;i<=n;i++)
	{
		if(fa(i)==i)
		{
			num[i][0]++;
		}else
		{
			num[fa(i)][r[i]]++;
		}
	}
	int maxans=0,minans=0,tot=1;
